mapper.select:
SELECT u.*
FROM `user` u,
     tenant t
WHERE u.tenant_id = t.id
  and u.username = #{username}
  and u.password = #{password}
  and u.status = 1
  and t.code = #{tenant_code}
  and u.delete_time is null;

SELECT u.*
FROM `user` u,
     tenant t
WHERE u.tenant_id = t.id
  and u.username = #{phone}
  and u.status = 1
  and t.code = #{tenant_code}
  and u.delete_time is null;

SELECT u.*
FROM `user` u,
     tenant t
WHERE u.tenant_id = t.id
  and u.openid = #{openid}
  and u.status = 1
  and t.code = #{tenant_code}
  and u.delete_time is null;
